// components/Auth.js
import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

export default function Auth() {
  const navigate = useNavigate();

  // Load the Spline Viewer script only once when component mounts
  useEffect(() => {
    // Check if the script is already loaded
    if (!document.querySelector('script[data-spline-viewer]')) {
      const script = document.createElement('script');
      script.type = 'module';
      script.src = 'https://unpkg.com/@splinetool/viewer@1.9.99/build/spline-viewer.js';
      script.setAttribute('data-spline-viewer', 'true');
      document.body.appendChild(script);
    }
  }, []);

  return (
    <div className="auth-container" style={{ position: 'relative', height: '100vh' }}>
      <h1>Welcome to Our App</h1>
      <div className="auth-options">
        <button onClick={() => navigate('/login')}>Login</button>
        <button onClick={() => navigate('/signup')}>Sign Up</button>
      </div>

      {/* Spline Viewer embedded */}
      <spline-viewer
        url="https://prod.spline.design/dNaQXegZafJWETXP/scene.splinecode"
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          zIndex: -1,
        }}
      ></spline-viewer>
    </div>
  );
}
